/**
 * AccountActor manages a single account's balance.
 *
 * CONCURRENCY SAFETY ANALYSIS:
 * 
 * Akka actors process one message at a time from their mailbox (the "actor model guarantee").
 * This means that within a single actor instance, there are NO concurrent modifications
 * to `balance` — each message is processed sequentially. Therefore, using `var balance`
 * inside an actor is safe as long as:
 *   1. The `balance` variable is NEVER accessed from outside the actor (e.g., via a Future callback
 *      that closes over it, or by exposing `this` to another thread).
 *   2. All state mutations happen strictly within the `receive` method (not in Future.onComplete, etc.).
 *   3. We use idempotency tracking to prevent duplicate transaction processing.
 *
 * INITIAL REVIEW FINDINGS & FIXES:
 * - Added idempotency tracking via `processedTransactions` to prevent duplicate deposits/withdrawals
 *   (e.g., if a message is retried by a supervisor or client).
 * - Added input validation (non-negative amounts).
 * - The check-then-act for withdrawal (check balance >= amount, then subtract) is safe here because
 *   Akka guarantees single-threaded message processing per actor instance. No lock needed.
 * - Ensured no Futures or callbacks close over mutable state.
 */
class AccountActor(accountId: String) extends Actor with ActorLogging {

  // Private mutable state — safe because Akka processes messages sequentially per actor.
  // NEVER close over this in a Future callback or share the actor's `this` reference.
  private var balance: BigDecimal = BigDecimal(0)

  // Idempotency: track processed transaction IDs to prevent double-processing.
  // In production, this would be bounded (e.g., LRU cache) or backed by a persistent store.
  private var processedTransactions: Map[String, AccountResponse] = Map.empty

  private val maxIdempotencyCache = 10000

  override def receive: Receive = {
    case Deposit(amount, txId) =>
      processedTransactions.get(txId) match {
        case Some(previousResponse) =>
          log.warning(s"[$accountId] Duplicate deposit transaction $txId — returning cached response.")
          sender() ! previousResponse

        case None =>
          if (amount <= 0) {
            val response = InvalidOperation(txId, s"Deposit amount must be positive, got: $amount")
            sender() ! response
          } else {
            balance += amount
            val response = DepositSuccess(txId, balance)
            cacheTransaction(txId, response)
            log.info(s"[$accountId] Deposit $amount (tx=$txId). New balance: $balance")
            sender() ! response
          }
      }

    case Withdraw(amount, txId) =>
      processedTransactions.get(txId) match {
        case Some(previousResponse) =>
          log.warning(s"[$accountId] Duplicate withdrawal transaction $txId — returning cached response.")
          sender() ! previousResponse

        case None =>
          if (amount <= 0) {
            val response = InvalidOperation(txId, s"Withdrawal amount must be positive, got: $amount")
            sender() ! response
          } else if (balance < amount) {
            // Check-then-act is safe here: Akka guarantees sequential message processing.
            val response = WithdrawFailure(txId, s"Insufficient funds. Required: $amount, Available: $balance", balance)
            cacheTransaction(txId, response)
            log.warning(s"[$accountId] Withdrawal of $amount denied (tx=$txId). Balance: $balance")
            sender() ! response
          } else {
            balance -= amount
            val response = WithdrawSuccess(txId, balance)
            cacheTransaction(txId, response)
            log.info(s"[$accountId] Withdrawal $amount (tx=$txId). New balance: $balance")
            sender() ! response
          }
      }

    case GetBalance(requestId) =>
      sender() ! BalanceResponse(requestId, balance)
  }

  private def cacheTransaction(txId: String, response: AccountResponse): Unit = {
    if (processedTransactions.size >= maxIdempotencyCache) {
      // Evict oldest entries (simple strategy; in production use an LRU cache)
      val toRemove = processedTransactions.size - maxIdempotencyCache + 1
      processedTransactions = processedTransactions.drop(toRemove)
    }
    processedTransactions += (txId -> response)
  }
}

