/**
 * AccountManager routes messages to per-account actors, ensuring each account
 * has exactly one actor (and thus one sequential message processor).
 */
class AccountManagerActor extends Actor with ActorLogging {

  private var accountActors: Map[String, ActorRef] = Map.empty

  override def receive: Receive = {
    case msg @ (Deposit(_, _) | Withdraw(_, _) | GetBalance(_)) =>
      // Extract account ID from a wrapper or use a convention.
      // Here we use a wrapper message.
      log.warning("AccountManagerActor received a message without account routing. Use AccountMessage wrapper.")

    case AccountManagerActor.RouteToAccount(accountId, message) =>
      val actorRef = accountActors.getOrElse(accountId, {
        val ref = context.actorOf(AccountActor.props(accountId), s"account-$accountId")
        accountActors += (accountId -> ref)
        log.info(s"Created actor for account $accountId")
        ref
      })
      actorRef.forward(message)
  }
}

